-- W1.6 questions batch 2039/9310 (10)

INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('diplomatic-9e854390-moex-00156', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-06c9aafe', 'sub-diplomatic-9e854390-01', NULL, 'single_choice', '氣候變遷與環境議題廣受全球各界的重視，下列相關陳述何者有誤？', '["聯合國大會在 1990 年決議設立「政府間氣候變化綱要公約談判委員會」（INC），並授權起草 有關氣候變化公約條文及所有認定為有必要的法律文件，該委員會於 1992 年通過「聯合國氣 候變化綱要公約」（UnitedNationsFrameworkConventiononClimateChange,UNFCCC）", "COP全名ConferenceoftheParties，是締約國會議，簽署UNFCCC的國家每年會召集締約國討 論如何共同應對氣候變遷。COP29將在2023年11月30日到12月12日首次在中東地區石油 產出國阿拉伯聯合大公國舉行", "歐盟的「邊境調整機制」（CarbonBorderAdjustmentMechanism,CBAM），與立法中的美國「清 潔競爭法案」（CleanCompetitionAct,CCA），皆是將氣候規則納入全球貿易的具體行動", "2050年達到二氧化碳淨零排放已是全球的共識，已有超過130個國家宣布推動在2050年前達 成。開發中國家則承諾較晚達到淨零碳排，例如中國承諾 2060 年達到淨零碳排，印度則預計 2070年達標"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:29+00:00", "source_pdf_sha1": "abdadf74bb7d", "answer_pdf_sha1": "988c750fb7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "0507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與國際現勢", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00157', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-06c9aafe', 'sub-diplomatic-9e854390-01', NULL, 'single_choice', '2023年5月下旬開始，世界外交可謂進入了超活躍期，下列有關各項峰會的敘述何者有誤？', '["5 月 18 日中國與中亞五國峰會在中國西安市舉行，會後發布的《西安宣言》顯示中國為了緩 解地緣矛盾的張力、決定以軍事安全的區域合作，打破地理空間阻隔，形成更大的操作空間", "5月19日7國集團峰會（G7）在日本廣島舉行，所公布的聯合文件《廣島願景》內容指出， 中國發展核武缺乏透明性，要求中國應公布核戰力資料，並對和平解決臺灣問題達成共識", "5月19日阿拉伯聯盟的22個會員國在沙烏地阿拉伯吉達市召開峰會。出席本次會議的兩位人 物引發格外關注，一是敘利亞總統阿薩德（Bashar al-Assad）；另一則是烏克蘭總統澤連斯基 （VolodymyrZelenskyy）", "5月22日印度與太平洋島國合作峰會（FIPIC）在巴布亞新幾內亞舉行，此乃第一次有印度總 理造訪巴國，顯示印度尋求強化與該區域的關係"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:29+00:00", "source_pdf_sha1": "abdadf74bb7d", "answer_pdf_sha1": "988c750fb7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "0507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與國際現勢", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00158', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-06c9aafe', 'sub-diplomatic-9e854390-01', NULL, 'single_choice', '有關「四方安全對話」（Quad）的陳述，下列何者錯誤？', '["由日本前首相安倍晉三於2007年發起", "是美國、日本、澳洲和紐西蘭之間的非正式戰略對話", "主張加強合作以維護區域和平與繁榮穩定", "有「亞洲版小北約」之名"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:29+00:00", "source_pdf_sha1": "abdadf74bb7d", "answer_pdf_sha1": "988c750fb7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "0507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與國際現勢", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00159', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-06c9aafe', 'sub-diplomatic-9e854390-01', NULL, 'single_choice', '下列關於《禁止生物武器公約》（BiologicalWeaponsConvention,BWC）的敘述，何者錯誤？', '["該公約全名為《禁止細菌（生物）及毒素武器的發展、生產及儲存以及銷毀該類武器的公約》 （ConventionontheProhibitionoftheDevelopment,ProductionandStockpilingofBacteriological （Biological）andToxinWeaponsandontheirDestruction）", "該公約於1972年開放簽署，並於1975年獲得22個國家批准後生效", "該公約是第一個禁止生產大規模殺傷性武器（weaponsofmassdestruction）的多邊裁軍條約", "該公約與化學武器或核武器相同，具備核查各國遵守情況的制度，以及有效實施核查的獨立國 際組織"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:29+00:00", "source_pdf_sha1": "abdadf74bb7d", "answer_pdf_sha1": "988c750fb7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "0507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與國際現勢", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00160', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-06c9aafe', 'sub-diplomatic-9e854390-01', NULL, 'single_choice', '在國際關係經典著作「權力與相互依賴」（Power and Interdependence）一書中，作者提出了「複 雜互賴」（complexinterdependence）概念以說明國際關係的新面貌，並指出其和現實主義的差異。 下列何項不屬複雜互賴理論的內容？', '["不同社會之間存在多種溝通管道，包括國家機關的不同部門和非國家行為者", "對大多數國際關係而言，軍事力量的重要性不可取代，安全始終是國家間最重要的議題", "國家總是相互依存，不同的議題領域呈現不同的互賴模式，複雜互賴的政治起源於這些差異", "任何議題都可能成為國際議程的首要問題，行為者如何促進議程設定（agenda-setting）成為重 要議題"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:29+00:00", "source_pdf_sha1": "abdadf74bb7d", "answer_pdf_sha1": "988c750fb7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "0507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與國際現勢", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00161', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-06c9aafe', 'sub-diplomatic-9e854390-01', NULL, 'single_choice', '「權力平衡」如何出現，下列學者的詮釋何者有誤？', '["摩根索（HansMorgenthau）認為，當各國在追求國家利益與權力時，權力平衡必定會出現", "懷特（MartinWight）認為，綜觀歷史顯示出來的趨勢是權力集中，而不是權力平均分布", "沃爾茲（KennethWaltz）認為，兩大超強都希望兩極平衡，解決方案是一起維持兩極平衡", "布爾（HedleyBull）認為，權力平衡是任何一種國際秩序所不可或缺的附屬品，各國明白這個 道理也願意共同追求，權力平衡才會出現並得以持續"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:29+00:00", "source_pdf_sha1": "abdadf74bb7d", "answer_pdf_sha1": "988c750fb7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "0507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與國際現勢", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00162', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-06c9aafe', 'sub-diplomatic-9e854390-01', NULL, 'single_choice', '下列關於二次大戰結束後歐洲整合與歐盟的說明，何者有誤？', '["三位歐洲整合之父是莫內（Monnet）、卡斯佩里（DeGasperi）與舒曼（Schuman）", "運用由上而下的功能主義思想，並吸收馬歇爾計畫的美國援助經驗，規劃出一條邁向歐洲整合 的道路", "歐盟現有27個成員國與4億人口，正式官方語言24種", "最早出現整合成功的機構是1952年成立的歐洲煤鋼共同體（EuropeanCoalandSteelCommunity）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:29+00:00", "source_pdf_sha1": "abdadf74bb7d", "answer_pdf_sha1": "988c750fb7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "0507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與國際現勢", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00163', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-06c9aafe', 'sub-diplomatic-9e854390-01', NULL, 'single_choice', '下列有關2023年7月11、12日舉行的北大西洋公約組織（NATO）峰會報導，那一項正確？', '["此次會議首度邀請澳大利亞、日本、紐西蘭和韓國等國家領導人出席", "此次會議在歐洲「反中急先鋒」的成員國家立陶宛首都維爾紐斯（Vilnius）舉行", "此次會議發表的〈戰略構想〉（StrategicConcept），稱中國「公開的野心和強制性政策」挑戰了 北約的利益", "此次會議發表的公報聲明，北約將於日本東京設立聯絡處，以加強北約與印太地區國家的合作"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:29+00:00", "source_pdf_sha1": "abdadf74bb7d", "answer_pdf_sha1": "988c750fb7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "0507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與國際現勢", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00164', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-06c9aafe', 'sub-diplomatic-9e854390-01', NULL, 'single_choice', '下列那一項聯合國決議呼籲開展南北對話，為南半球低度開發國家（less-developedcountries）能 更充分地參與國際經濟政策的制定開闢途徑？', '["國際經濟新秩序（NewInternationalEconomicOrder）", "邁向國際經濟新秩序（TowardsaNewInternationalEconomicOrder）", "可持續發展決議（SustainableDevelopmentResolution）", "經濟對話倡議（EconomicDialogueInitiative）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:29+00:00", "source_pdf_sha1": "abdadf74bb7d", "answer_pdf_sha1": "988c750fb7be", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "0507", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與國際現勢", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00165', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-112-d35177eb', 'sub-diplomatic-9e854390-02', NULL, 'essay', '藍天公司 X2年與 X1 年資產負債表之部分資料如下：
X2/12/31 X1/12/31
應收帳款 $110,000 $106,000
存貨 48,000 42,000
流動負債 48,000 86,000
非流動負債 180,000 190,000
股東權益 652,000 644,000
藍天公司日常均以賒銷模式銷售商品。藍天公司 X2 年利息費用為
$12,500，所得稅率為 20%，且經分析得知 X2年該公司之應收帳款週轉
率為 10次、存貨週轉率為16 次、淨利率為15%。
試作：
計算藍天公司 X2 年銷貨收入、銷貨成本、利息保障倍數、資產週轉
率及股東權益報酬率。（15 分）（需列示計算過程，否則不予計分）
藍天公司之競爭對手碧海公司在 X2 年之負債比率為 38%、利息保障
倍數為 11倍。試比較藍天公司與碧海公司之長期償債能力。（5 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:30+00:00", "source_pdf_sha1": "873fbf1da003", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "201", "s": "1305", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "會計學概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL)
